def _expand_facts(base_facts: List[FactTuple], min_count: int, templates: List[str]) -> List[FactTuple]:
    expanded: List[FactTuple] = []
    for q, ans, distractors, difficulty in base_facts:
        for template in templates:
            expanded.append((template.format(q=q), ans, list(distractors), difficulty))
    if len(expanded) < min_count:
        raise ValueError(f"Need at least {min_count} tuples, got {len(expanded)}")
    return expanded[:min_count]


